 1	import React, { FC, Ref, useState } from 'react';
 2	
 3	import {
 4	  Dropdown,
 5	  DropdownItem,
 6	  DropdownList,
 7	  MenuToggle,
 8	  MenuToggleElement,
 9	} from '@patternfly/react-core';
10	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
11	
12	import { NetworkPolicyPeerType } from './utils/types';
13	
14	type NetworkPolicyAddPeerDropdownProps = {
15	  onSelect: (type: NetworkPolicyPeerType) => void;
16	  title: string;
17	};
18	
19	const NetworkPolicyAddPeerDropdown: FC<NetworkPolicyAddPeerDropdownProps> = (props) => {
20	  const { t } = useNetworkingTranslation();
21	  const { onSelect, title } = props;
22	
23	  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
24	
25	  return (
26	    <div className="form-group co-create-networkpolicy__add-peer">
27	      <Dropdown
28	        data-test="add-peer"
29	        isOpen={isDropdownOpen}
30	        onSelect={(_event, networkType: NetworkPolicyPeerType) => {
31	          onSelect(networkType);
32	          setIsDropdownOpen(false);
33	        }}
34	        toggle={(toggleRef: Ref<MenuToggleElement>) => (
35	          <MenuToggle
36	            id="toggle-basic"
37	            isExpanded={isDropdownOpen}
38	            onClick={() => setIsDropdownOpen(!isDropdownOpen)}
39	            ref={toggleRef}
40	          >
41	            {title}
42	          </MenuToggle>
43	        )}
44	      >
45	        <DropdownList className="add-peer-dropdown">
46	          <DropdownItem value="sameNS">{t('Allow pods from the same namespace')}</DropdownItem>
47	          <DropdownItem value="anyNS">{t('Allow pods from inside the cluster')}</DropdownItem>
48	          <DropdownItem value="ipblock">{t('Allow peers by IP block')}</DropdownItem>
49	        </DropdownList>
50	      </Dropdown>
51	    </div>
52	  );
53	};
54	
55	export default NetworkPolicyAddPeerDropdown;

